"use client";

import { useEffect, useMemo, useRef, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { format, isToday, isYesterday } from 'date-fns';
import {
  ArrowLeft,
  CheckCheck,
  FileText,
  MessageCircle,
  Paperclip,
  Search,
  Send,
  Video,
  Zap,
} from 'lucide-react';
import { Conversation, Message, Appointment } from '@/types';
import { chatService } from '@/services/chatService';
import { appointmentService } from '@/services/appointmentService';
import { useAuthStore } from '@/store';
import { useToast } from '@/hooks/use-toast';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import DocumentComposer from '@/components/doctor/DocumentComposer';
import VideoConsultModal from '@/components/doctor/VideoConsultModal';
import { useRecordsStore } from '@/store/recordsStore';
import { sendPrescription, sendLabRequest, sendMedicalCertificate } from '../../../../features/doctor/consult/actions';
import { sendMessage, attachDocument } from '../../../../features/doctor/messages/actions';

function formatTime(ts: string) {
  const d = new Date(ts);
  if (isToday(d)) return format(d, 'h:mm a');
  if (isYesterday(d)) return 'Yesterday';
  return format(d, 'MMM d');
}

const quickReplies = [
  'Thanks for the update.',
  'Please upload your latest labs.',
  'I will review and reply shortly.',
];

const onlineStatus = (id?: string) => {
  if (!id) return false;
  const hash = id.split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
  return hash % 2 === 0;
};

export default function DoctorMessagesPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { user } = useAuthStore();
  const { toast } = useToast();
  const { addPrescriptionFromConsult, addLabResultFromConsult, addCertificateFromConsult } = useRecordsStore();

  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [active, setActive] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [text, setText] = useState('');
  const [loadingList, setLoadingList] = useState(true);
  const [loadingChat, setLoadingChat] = useState(false);
  const [showDocuments, setShowDocuments] = useState(false);
  const [showVideo, setShowVideo] = useState(false);
  const [activeAppointment, setActiveAppointment] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [showList, setShowList] = useState(true);
  const [typing, setTyping] = useState(false);
  const [readIds, setReadIds] = useState<Record<string, boolean>>({});
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetch = async () => {
      if (!user) return;
      setLoadingList(true);
      const res = await chatService.getConversations(user.id);
      if (res.success) {
        const sorted = [...res.data].sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
        setConversations(sorted);
        const requested = searchParams.get('conversation');
        const matched = requested ? sorted.find((c) => c.id === requested) : null;
        const initial = matched || sorted[0] || null;
        setActive(initial);
        if (initial) setShowList(false);
      }
      setLoadingList(false);
    };
    fetch();
  }, [user, searchParams]);

  useEffect(() => {
    const loadMessages = async () => {
      if (!active) return;
      setLoadingChat(true);
      const res = await chatService.getMessages(active.id);
      if (res.success) {
        setMessages(res.data);
        setReadIds((prev) => ({
          ...prev,
          ...res.data.reduce((acc, msg) => {
            acc[msg.id] = msg.senderId === user?.id ? true : acc[msg.id];
            return acc;
          }, {} as Record<string, boolean>),
        }));
      }
      setLoadingChat(false);
    };
    loadMessages();
  }, [active?.id, user?.id]);

  useEffect(() => {
    const loadAppointment = async () => {
      if (!user || !active) return;
      const res = await appointmentService.getAppointments({ doctorId: user.id, patientId: active.patientId });
      if (res.success && res.data.length > 0) {
        const upcoming = res.data.find((a) => ['confirmed', 'in-progress'].includes(a.status));
        setActiveAppointment(upcoming || res.data[0]);
      } else {
        setActiveAppointment(null);
      }
    };
    loadAppointment();
  }, [active?.id, user]);

  useEffect(() => {
    if (!scrollRef.current) return;
    scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, typing]);

  const handleSelectConversation = (conv: Conversation) => {
    setActive(conv);
    setShowList(false);
    setConversations((prev) =>
      prev.map((c) => (c.id === conv.id ? { ...c, unreadCount: 0 } : c))
    );
  };

  const handleSend = async (content?: string) => {
    if (!user || !active) return;
    const payload = (content ?? text).trim();
    if (!payload) return;
    const res = await chatService.sendMessage(active.id, user.id, 'doctor', payload, 'text');
    await sendMessage(active.id, user.id, payload);
    if (res.success) {
      setMessages((prev) => [...prev, res.data]);
      setText('');
      setReadIds((prev) => ({ ...prev, [res.data.id]: false }));
      setConversations((prev) =>
        prev.map((c) => (c.id === active.id ? { ...c, lastMessage: res.data, updatedAt: res.data.timestamp } : c))
      );
      setTyping(true);
      setTimeout(() => {
        setTyping(false);
        const reply: Message = {
          id: `msg-${Date.now()}`,
          conversationId: active.id,
          senderId: active.patientId,
          senderRole: 'patient',
          content: 'Thanks doc, will do.',
          type: 'text',
          isRead: false,
          timestamp: new Date().toISOString(),
        };
        setMessages((prev) => [...prev, reply]);
      }, 1400);
      setTimeout(() => {
        setReadIds((prev) => ({ ...prev, [res.data.id]: true }));
      }, 900);
    }
  };

  const sendDocs = async (payload: { type: 'rx' | 'lab' | 'cert'; data: any }) => {
    if (!activeAppointment || !user) return;
    if (payload.type === 'rx') {
      const rx = await sendPrescription({
        appointmentId: activeAppointment.id,
        patientId: activeAppointment.patientId,
        doctorId: user.id,
        diagnosis: payload.data.diagnosis,
        medications: payload.data.medications,
        instructions: payload.data.instructions,
      });
      addPrescriptionFromConsult(rx);
      await attachDocument(active?.id || '', user.id, rx.id);
    }
    if (payload.type === 'lab') {
      const lab = await sendLabRequest({
        appointmentId: activeAppointment.id,
        patientId: activeAppointment.patientId,
        doctorId: user.id,
        testName: payload.data.testName,
        notes: payload.data.notes,
      });
      addLabResultFromConsult(lab);
      await attachDocument(active?.id || '', user.id, lab.id);
    }
    if (payload.type === 'cert') {
      const cert = await sendMedicalCertificate({
        appointmentId: activeAppointment.id,
        patientId: activeAppointment.patientId,
        doctorId: user.id,
        purpose: payload.data.purpose,
        diagnosis: payload.data.diagnosis,
        restDays: payload.data.restDays,
      });
      addCertificateFromConsult(cert);
      await attachDocument(active?.id || '', user.id, cert.id);
    }
    await chatService.sendMessage(active?.id || '', user.id, 'doctor', 'Document sent. Please check My Files.', 'file');
    toast({ title: 'Document sent', description: 'Patient file updated.' });
  };

  const filtered = useMemo(() => {
    if (!searchQuery) return conversations;
    const q = searchQuery.toLowerCase();
    return conversations.filter((c) =>
      c.patient?.name?.toLowerCase().includes(q) ||
      c.lastMessage?.content?.toLowerCase().includes(q)
    );
  }, [conversations, searchQuery]);

  const activeOnline = onlineStatus(active?.patientId);

  return (
    <div className="lg:grid lg:grid-cols-[320px_1fr] gap-4 h-[calc(100vh-9rem)] flex flex-col">
      <Card className={`overflow-hidden ${showList ? 'block' : 'hidden'} lg:block`}>
        <CardContent className="p-0 flex flex-col h-full">
          <div className="p-4 border-b">
            <h2 className="text-lg font-semibold">Messages</h2>
            <p className="text-xs text-muted-foreground">Patient conversations</p>
            <div className="relative mt-3">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search patients..."
                className="pl-10"
              />
            </div>
          </div>
          <ScrollArea className="flex-1">
            {loadingList ? (
              <div className="p-4 space-y-3">
                {[1, 2, 3].map((i) => (
                  <Skeleton key={i} className="h-16 rounded-xl" />
                ))}
              </div>
            ) : filtered.length === 0 ? (
              <div className="p-6 text-center text-sm text-muted-foreground space-y-3">
                <MessageCircle className="h-10 w-10 mx-auto opacity-40" />
                <p>No messages yet.</p>
                <Button size="sm" variant="outline" onClick={() => router.push('/doctor/queue')}>
                  View Queue
                </Button>
              </div>
            ) : (
              filtered.map((conv) => {
                const patient = conv.patient;
                const isActive = active?.id === conv.id;
                const isOnline = onlineStatus(conv.patientId);
                return (
                  <button
                    key={conv.id}
                    onClick={() => handleSelectConversation(conv)}
                    className={`w-full text-left p-4 border-b hover:bg-muted/40 transition-colors ${isActive ? 'bg-muted' : ''}`}
                  >
                    <div className="flex items-center gap-3">
                      <div className="relative">
                        <Avatar className="h-9 w-9">
                          <AvatarImage src={patient?.avatar} />
                          <AvatarFallback>{patient?.name?.[0]}</AvatarFallback>
                        </Avatar>
                        <span className={`absolute -bottom-0.5 -right-0.5 h-2.5 w-2.5 rounded-full border border-background ${isOnline ? 'bg-success' : 'bg-muted-foreground/40'}`} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">{patient?.name}</p>
                        <p className="text-xs text-muted-foreground truncate">{conv.lastMessage?.content ?? 'No messages yet'}</p>
                      </div>
                      <div className="flex flex-col items-end gap-1">
                        <span className="text-[10px] text-muted-foreground">{formatTime(conv.updatedAt)}</span>
                        {conv.unreadCount > 0 && (
                          <Badge className="bg-primary text-primary-foreground text-[10px] h-4 px-1.5">
                            {conv.unreadCount}
                          </Badge>
                        )}
                      </div>
                    </div>
                  </button>
                );
              })
            )}
          </ScrollArea>
        </CardContent>
      </Card>

      <Card className={`flex flex-col overflow-hidden ${showList ? 'hidden' : 'flex'} lg:flex`}>
        <CardContent className="p-0 flex flex-col h-full">
          <div className="p-4 border-b flex items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <Button variant="ghost" size="icon" className="lg:hidden" onClick={() => setShowList(true)}>
                <ArrowLeft className="h-4 w-4" />
              </Button>
              <div className="relative">
                <Avatar className="h-10 w-10">
                  <AvatarImage src={active?.patient?.avatar} />
                  <AvatarFallback>{active?.patient?.name?.[0]}</AvatarFallback>
                </Avatar>
                <span className={`absolute -bottom-0.5 -right-0.5 h-2.5 w-2.5 rounded-full border border-background ${activeOnline ? 'bg-success' : 'bg-muted-foreground/40'}`} />
              </div>
              <div>
                <p className="font-medium">{active?.patient?.name ?? 'Select a patient'}</p>
                <p className="text-xs text-muted-foreground">
                  {activeOnline ? 'Online' : 'Offline'} • {activeAppointment?.type === 'online' ? 'Video consult' : 'In-clinic'}
                </p>
              </div>
            </div>
            <div className="flex gap-2">
              <Button size="sm" variant="outline" className="gap-1" onClick={() => setShowDocuments(true)} disabled={!activeAppointment}>
                <FileText className="h-3.5 w-3.5" />
                Attach
              </Button>
              <Button size="sm" className="gap-1" onClick={() => setShowVideo(true)} disabled={!activeAppointment || activeAppointment.type !== 'online'}>
                <Video className="h-3.5 w-3.5" />
                Start Video
              </Button>
            </div>
          </div>

          <ScrollArea className="flex-1 p-4">
            {!active ? (
              <div className="h-full flex flex-col items-center justify-center text-sm text-muted-foreground space-y-3">
                <MessageCircle className="h-10 w-10 opacity-40" />
                <p>Select a conversation to start messaging.</p>
              </div>
            ) : loadingChat ? (
              <div className="space-y-3">
                <Skeleton className="h-12 w-2/3 rounded-xl" />
                <Skeleton className="h-12 w-1/2 rounded-xl ml-auto" />
                <Skeleton className="h-12 w-3/4 rounded-xl" />
              </div>
            ) : (
              <div ref={scrollRef} className="space-y-3">
                {messages.map((msg) => {
                  const isOwn = msg.senderId === user?.id;
                  return (
                    <div key={msg.id} className={`flex ${isOwn ? 'justify-end' : 'justify-start'}`}>
                      <div className={`px-4 py-2 rounded-2xl text-sm max-w-[75%] ${isOwn ? 'bg-primary text-primary-foreground' : 'bg-muted'}`}>
                        <div className="flex items-center gap-2">
                          {msg.type === 'file' && <Paperclip className="h-3.5 w-3.5" />}
                          <span>{msg.content}</span>
                        </div>
                        <div className={`text-[10px] mt-1 flex items-center gap-1 ${isOwn ? 'text-primary-foreground/70' : 'text-muted-foreground'}`}>
                          {formatTime(msg.timestamp)}
                          {isOwn && (
                            <CheckCheck className={`h-3 w-3 ${readIds[msg.id] ? 'opacity-100' : 'opacity-50'}`} />
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
                {typing && (
                  <div className="text-xs text-muted-foreground">Patient is typing...</div>
                )}
              </div>
            )}
          </ScrollArea>

          <div className="p-3 border-t space-y-2">
            <div className="flex flex-wrap gap-2">
              {quickReplies.map((reply) => (
                <Button key={reply} size="sm" variant="outline" onClick={() => handleSend(reply)}>
                  {reply}
                </Button>
              ))}
            </div>
            <div className="flex gap-2">
              <Button variant="outline" size="icon" onClick={() => setShowDocuments(true)} disabled={!activeAppointment}>
                <Paperclip className="h-4 w-4" />
              </Button>
              <Input
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Type a message..."
                onKeyDown={(e) => { if (e.key === 'Enter') handleSend(); }}
              />
              <Button onClick={() => handleSend()} disabled={!text.trim()}>
                <Send className="h-4 w-4" />
              </Button>
            </div>
            <p className="text-[11px] text-muted-foreground flex items-center gap-1">
              <Zap className="h-3 w-3" />
              All messages are secure and confidential.
            </p>
          </div>
        </CardContent>
      </Card>

      <Dialog open={showDocuments} onOpenChange={setShowDocuments}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Attach Document</DialogTitle>
          </DialogHeader>
          {activeAppointment ? (
            <DocumentComposer
              onSendPrescription={(data) => sendDocs({ type: 'rx', data })}
              onSendLab={(data) => sendDocs({ type: 'lab', data })}
              onSendCertificate={(data) => sendDocs({ type: 'cert', data })}
            />
          ) : (
            <div className="text-sm text-muted-foreground">Select a patient first.</div>
          )}
        </DialogContent>
      </Dialog>

      <VideoConsultModal
        open={showVideo}
        appointment={activeAppointment}
        onClose={() => setShowVideo(false)}
        onEnd={async () => {
          setShowVideo(false);
          if (active && user) {
            await chatService.sendMessage(
              active.id,
              user.id,
              'doctor',
              'Video consultation ended. Transcript saved.',
              'system'
            );
          }
          toast({ title: 'Consult ended', description: 'Transcript sent to patient.' });
        }}
        onSendPrescription={(data) => sendDocs({ type: 'rx', data })}
        onSendLab={(data) => sendDocs({ type: 'lab', data })}
        onSendCertificate={(data) => sendDocs({ type: 'cert', data })}
      />
    </div>
  );
}
